input.content:
@page {
  size: A4;
  margin: 18mm 16mm 20mm 16mm;
}

body {
  font-family: 'Segoe UI', 'Inter', 'Helvetica Neue', Arial, sans-serif;
  font-size: 11pt;
  line-height: 1.65;
  color: #1f2937;
  max-width: none;
  padding: 0;
  margin: 0;
}

h1 {
  font-size: 24pt;
  color: #0f172a;
  border-bottom: 3px solid #2563eb;
  padding-bottom: 8px;
  margin-top: 28px;
  margin-bottom: 14px;
  page-break-after: avoid;
  page-break-before: always;
}

h1:first-of-type {
  page-break-before: avoid;
}

h2 {
  font-size: 16pt;
  color: #1e3a8a;
  margin-top: 26px;
  margin-bottom: 10px;
  padding-left: 10px;
  border-left: 4px solid #2563eb;
  page-break-after: avoid;
}

h3 {
  font-size: 13pt;
  color: #334155;
  margin-top: 18px;
  margin-bottom: 8px;
  page-break-after: avoid;
}

p {
  margin: 8px 0;
  text-align: justify;
}

strong {
  color: #0f172a;
}

blockquote {
  border-left: 4px solid #60a5fa;
  background: #eff6ff;
  margin: 14px 0;
  padding: 12px 16px;
  color: #1e3a8a;
  font-style: italic;
  border-radius: 0 6px 6px 0;
  page-break-inside: avoid;
}

blockquote p {
  margin: 4px 0;
}

ul, ol {
  margin: 8px 0 12px 0;
  padding-left: 24px;
}

li {
  margin: 5px 0;
}

code {
  background: #f1f5f9;
  color: #be185d;
  padding: 1px 6px;
  border-radius: 4px;
  font-family: 'Consolas', 'Fira Code', 'Courier New', monospace;
  font-size: 9.5pt;
}

pre {
  background: #0f172a;
  color: #e2e8f0;
  padding: 14px 16px;
  border-radius: 8px;
  overflow-x: auto;
  font-size: 9.5pt;
  line-height: 1.5;
  margin: 12px 0;
  page-break-inside: avoid;
  font-family: 'Consolas', 'Fira Code', 'Courier New', monospace;
}

pre code {
  background: transparent;
  color: inherit;
  padding: 0;
  font-size: inherit;
}

table {
  border-collapse: collapse;
  width: 100%;
  margin: 14px 0;
  font-size: 10pt;
  page-break-inside: avoid;
}

th {
  background: #2563eb;
  color: white;
  padding: 10px;
  text-align: left;
  font-weight: 600;
}

td {
  border: 1px solid #e2e8f0;
  padding: 8px 10px;
}

tr:nth-child(even) td {
  background: #f8fafc;
}

hr {
  border: 0;
  border-top: 1px solid #cbd5e1;
  margin: 24px 0;
}

a {
  color: #2563eb;
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

/* Title page styling — first H1 */
body > h1:first-child {
  font-size: 28pt;
  text-align: center;
  border-bottom: none;
  margin-top: 40px;
  color: #1e3a8a;
}

/* Make emoji markers stand out */
li strong, p strong {
  font-weight: 600;
}

/* Avoid orphan headings */
h2 + p, h3 + p {
  page-break-before: avoid;
}

